+    };
+
+    if **left == key_expr && planner_directive_index_probe_constant(right) {
+        return Some(right.as_ref().clone());
+    }
+    if **right == key_expr && planner_directive_index_probe_constant(left) {
+        return Some(left.as_ref().clone());
+    }
