+                PlannerIndexRangeBound {
+                    expr: right.clone(),
+                    inclusive: false,
+                },
+            )),
+            Le => Some((
+                PlannerExpressionIndexRangeSlot::Upper,
+                PlannerIndexRangeBound {
+                    expr: right.clone(),
+                    inclusive: true,
+                },
+            )),
+            Lt => Some((
