+fn planner_assign_expression_index_range_bound(
+    target: &mut PlannerIndexRangeTarget,
+    slot: PlannerExpressionIndexRangeSlot,
+    bound: PlannerIndexRangeBound,
+) -> bool {
+    let target_slot = match slot {
+        PlannerExpressionIndexRangeSlot::Lower => &mut target.lower,
+        PlannerExpressionIndexRangeSlot::Upper => &mut target.upper,
+    };
+    if target_slot.is_some() {
+        false
+    } else {
+        *target_slot = Some(bound);
+        true
+    }
